// Extract error type and message from Telegram update
const body = $json.message || $json.body;
const text = body?.text || '';
const timestamp = new Date().toISOString();
const errorHash = require('crypto').createHash('md5').update(text).digest('hex').substring(0, 8);

// Classify error type
let errorType = 'unknown';
let severity = 'low';
let autoRecoveryPossible = false;

if (text.match(/LaunchAgent|launchctl|bootout/i)) {
  errorType = 'launchagent_crash';
  severity = 'critical';
  autoRecoveryPossible = true;
} else if (text.match(/timeout|timed out|n8n.*timeout/i)) {
  errorType = 'n8n_timeout';
  severity = 'high';
  autoRecoveryPossible = true;
} else if (text.match(/log|disk full|rotation|storage/i)) {
  errorType = 'log_overflow';
  severity = 'medium';
  autoRecoveryPossible = true;
} else if (text.match(/API|HTTP|connection|refused|unreachable/i)) {
  errorType = 'api_unavailable';
  severity = 'high';
  autoRecoveryPossible = false;
} else if (text.match(/out of memory|OOM|memory error/i)) {
  errorType = 'oom_error';
  severity = 'critical';
  autoRecoveryPossible = false;
}

return {
  originalMessage: text,
  errorType: errorType,
  severity: severity,
  timestamp: timestamp,
  errorHash: errorHash,
  autoRecoveryPossible: autoRecoveryPossible,
  chatId: body?.chat?.id || process.env.TELEGRAM_CHAT_ID,
  messageId: body?.message_id
};

// Check if error occurred 3+ times in last 1 hour
const errorHash = $json.errorHash;
const timestamp = new Date($json.timestamp);
const oneHourAgo = new Date(timestamp - 60 * 60 * 1000);

// In production, this would query Mem0 or a cache
// For now, we'll use a simple flag based on error frequency
// This should be enhanced with actual Mem0 MCP calls

return {
  ...($json),
  shouldAutoProcess: true,
  errorCount: 1,  // placeholder - would be queried from Mem0
  lastOccurrence: timestamp.toISOString(),
  note: 'Deduplication logic should integrate with Mem0 MCP for production'
};

const result = $json;
const success = result.exitCode === 0;

return {
  ...($inputWithIndex[0].json),
  recoveryAttempt: 'launchagent_bootout',
  recoverySuccess: success,
  recoveryOutput: result.stdout || result.stderr || 'Unknown result',
  recoveryTimestamp: new Date().toISOString()
};

const response = $json;

return {
  ...($inputWithIndex[0].json),
  recoveryAttempt: 'n8n_retry_api',
  recoverySuccess: response.status === 'ok' || Array.isArray(response),
  recoveryOutput: `Retrieved execution history`,
  recoveryTimestamp: new Date().toISOString()
};

const result = $json;
const success = result.exitCode === 0;

return {
  ...($inputWithIndex[0].json),
  recoveryAttempt: 'log_rotation',
  recoverySuccess: success,
  recoveryOutput: result.stdout || result.stderr || 'Rotation completed',
  recoveryTimestamp: new Date().toISOString()
};

